VALUES ('91bc9b6c-e084-457f-9828-c3899110568c', 1465, 'Asian Operatic Museum', '2026-06-04T23:43:33.453Z', '{"zones":[["Hero Hologram Experience","hero-hologram-sang-nila-utama","hologram","Sang Nila Utama appears as a full-body hologram to welcome visitors into the origin story of Singapore through myth, memory, leadership, and maritime imagination."],["Immersive Interactive Zone","immersive-interactive-zone","xr_led_ar_vr_tactile","A multi-sensory zone where visitors move through LED storytelling, AR screens, seated VR games, and tactile tabletop interactions connected to the 5 Kings narrative."],["Mulan Experience Zone","mulan-experience-zone","hologram_ar_storytelling","A cultural heroism zone exploring courage, identity, loyalty, disguise, family duty, and performance through hologram artefacts, full-body character storytelling, and AR screen interaction."],["XRetail Cultural Marketplace","xretail-cultural-marketplace","commerce_ar_ai","A storytelling commerce layer where museum products, cultural artefacts, educational kits, costumes, books, and digital collectibles are sold with emotional cultural context."],["XLearning Academy","xlearning-academy","learning_certification","A learning layer for students, visitors, teachers, guides, internal staff, and future franchise consultants."],["XGaming Quest Layer","xgaming-quest-layer","gamification","A mission-based cultural learning game where visitors earn badges by completing story paths, AR discoveries, quizzes, and exhibit challenges."]],"steps":14,"seed_source":"SCAVERSE_TOTAL_DATABASE_SEED"}'::jsonb, 88, 'walkthrough', 86, true, 'healthy', '6a220da6deec1196adc0ddee', '2026-06-04T23:43:34.259000', '2026-06-04T23:43:34.259000')
